@api.constrains('project_id', 'lead_id')
def _check_project_or_lead(self):
    for record in self:
        if not record.project_id and not record.lead_id:
            raise ValidationError(_('A bond must be linked to either a Project or a CRM Lead/Opportunity.'))

@api.model_create_multi
def create(self, vals_list):
    """Override create to log bond creation in project"""
    records = super(ProjectBonding, self).create(vals_list)
    for record in records:
        if record.project_id:
            record.project_id.message_post(
                body=_('Bond created: <b>%s</b> (%s) - Amount: %s %s') % (
                    record.name,
                    record.bonding_type_id.name,
                    record.amount or 0,
                    record.currency_id.symbol
                ),
                subject=_('Bond Created: %s') % record.name,
                message_type='notification',
                subtype_xmlid='mail.mt_note'
            )
    return records

def write(self, vals):
    """Override write to log bond modifications in project"""
    result = super(ProjectBonding, self).write(vals)
    for record in self:
        if record.project_id:
            # Build message for changed fields
            changes = []
            if 'state' in vals:
                changes.append(_('Status changed to <b>%s</b>') % dict(record._fields['state'].selection).get(record.state))
            if 'amount' in vals:
                changes.append(_('Amount updated to <b>%s %s</b>') % (record.amount, record.currency_id.symbol))
            if 'due_date' in vals:
                changes.append(_('Due date set to <b>%s</b>') % (record.due_date or 'Not set'))
            if 'expiry_date' in vals:
                changes.append(_('Expiry date set to <b>%s</b>') % (record.expiry_date or 'Not set'))
            if 'date_issued' in vals:
                changes.append(_('Issue date set to <b>%s</b>') % (record.date_issued or 'Not set'))

            if changes:
                record.project_id.message_post(
                    body=_('Bond <b>%s</b> updated:<br/>%s') % (record.name, '<br/>'.join(changes)),
                    subject=_('Bond Updated: %s') % record.name,
                    message_type='notification',
                    subtype_xmlid='mail.mt_note'
                )
    return result

def unlink(self):
    """Override unlink to log bond deletion in project"""
    # Store project info before deletion
    project_logs = []
    for record in self:
        if record.project_id:
            project_logs.append({
                'project': record.project_id,
                'name': record.name,
                'bonding_type': record.bonding_type_id.name,
                'amount': record.amount,
                'currency': record.currency_id.symbol
            })

    result = super(ProjectBonding, self).unlink()

    # Log after deletion
    for log in project_logs:
        log['project'].message_post(
            body=_('Bond deleted: <b>%s</b> (%s) - Amount: %s %s') % (
                log['name'],
                log['bonding_type'],
                log['amount'] or 0,
                log['currency']
            ),
            subject=_('Bond Deleted: %s') % log['name'],
            message_type='notification',
            subtype_xmlid='mail.mt_note'
        )

    return result

