def _log_checklist_changes(self, new_vals, old_vals):
    """Log checklist item changes to the CRM lead's chatter"""
    self.ensure_one()

    if not self.lead_id:
        return

    changes = []
    user = self.env.user

    # Track status changes
    if 'status' in new_vals and old_vals.get('status') != self.status:
        status_labels = dict(self._fields['status'].selection)
        old_status = status_labels.get(old_vals.get('status'), 'Unknown')
