"""Partner extensions: subcontractor checklist sync and stored compliance status."""

from odoo import api, fields, models


class ResPartner(models.Model):
    _inherit = "res.partner"

    subcontractor_requirement_line_ids = fields.One2many(
        "partner.subcontractor.requirement.line",
        "partner_id",
        string="Subcontractor requirement checklist",
    )
    subcontractor_requirements_state = fields.Selection(
        selection=[
            ("none", "No requirements"),
            ("incomplete", "Requirements pending"),
            ("met", "Requirements met"),
        ],
        string="Subcontractor requirements status",
        default="none",
        store=True,
        index=True,
        help="Compliance with the global subcontractor checklist (Contact Type = Subcontractor).",
    )
    show_subcontractor_requirements = fields.Boolean(
        compute="_compute_show_subcontractor_requirements",
    )

    @api.model
    def _subcontractor_type_record(self):
        return self.env.ref(
            "contacts_type.contact_type_subcontractor", raise_if_not_found=False
        )

    @api.model
    def _subcontractor_partner_domain(self):
        """Domain for partners that should receive requirement lines."""
        sub_type = self._subcontractor_type_record()
        if sub_type:
            return [("contact_type_id", "=", sub_type.id)]
        return [("contact_type_id.name", "=ilike", "Subcontractor")]

    def _is_subcontractor_contact(self):
        self.ensure_one()
        sub_type = self._subcontractor_type_record()
        if sub_type:
            return self.contact_type_id == sub_type
        ct = self.contact_type_id
        return bool(ct and ct.name and ct.name.strip().lower() == "subcontractor")

    @api.depends("contact_type_id")
    def _compute_show_subcontractor_requirements(self):
        for partner in self:
            partner.show_subcontractor_requirements = partner._is_subcontractor_contact()

    @api.depends(
        "contact_type_id",
        "subcontractor_requirement_line_ids",
        "subcontractor_requirement_line_ids.done",
        "subcontractor_requirement_line_ids.not_applicable",
        "subcontractor_requirement_line_ids.is_optional",
        "subcontractor_requirement_line_ids.is_active",
    )
    def _compute_subcontractor_requirements_state(self):
        for partner in self:
            if not partner._is_subcontractor_contact():
                partner.subcontractor_requirements_state = "none"
                continue
            lines = partner.subcontractor_requirement_line_ids
            if not lines:
                partner.subcontractor_requirements_state = "none"
                continue
            # Blocking = active template row and not marked optional on template.
            blocking = lines.filtered(lambda l: l.is_active and not l.is_optional)
            if not blocking:
                partner.subcontractor_requirements_state = "met"
                continue
            if all(line.done or line.not_applicable for line in blocking):
                partner.subcontractor_requirements_state = "met"
            else:
                partner.subcontractor_requirements_state = "incomplete"

    def _sync_subcontractor_requirement_lines(self):
        """Append missing lines from the global template for subcontractor contacts.

        We only create rows for template items not yet linked; we do not delete partner
        lines when template items are removed (audit / user progress preserved).
        """
        Line = self.env["partner.subcontractor.requirement.line"]
        Template = self.env["subcontractor.requirement.template.item"]
        for partner in self:
            if not partner._is_subcontractor_contact():
                continue
            templates = Template.search([])
            if not templates:
                continue
            existing = set(partner.subcontractor_requirement_line_ids.mapped("template_item_id").ids)
            for tmpl in templates:
                if tmpl.id in existing:
                    continue
                Line.create(
                    {
                        "partner_id": partner.id,
                        "template_item_id": tmpl.id,
                        "sequence": tmpl.sequence,
                    }
                )
        # Lines are created after super().create/write; refresh stored state in the same transaction.
        if self:
            self._compute_subcontractor_requirements_state()

    @api.model_create_multi
    def create(self, vals_list):
        partners = super().create(vals_list)
        partners._sync_subcontractor_requirement_lines()
        return partners

    def write(self, vals):
        res = super().write(vals)
        if "contact_type_id" in vals or "active" in vals:
            self._sync_subcontractor_requirement_lines()
        return res

